void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Garcia_1");			link.l1 = StringFromKey("Garcia_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Garcia_3");			link.l1 = StringFromKey("Garcia_4");			link.l1.go = "exit";			AddDialogExitQuest("FL8_s19a");		break;		case "2":			dialog.text = StringFromKey("Garcia_5");			link.l1 = StringFromKey("Garcia_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Garcia_7");			link.l1 = StringFromKey("Garcia_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("Garcia_9");			link.l1 = StringFromKey("Garcia_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("Garcia_11");			link.l1 = StringFromKey("Garcia_12");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("Garcia_13");			link.l1 = StringFromKey("Garcia_14");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("Garcia_15");			link.l1 = StringFromKey("Garcia_16");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}